#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::atomic::{AtomicUsize, Ordering};

    // -- Sync tests --

    #[test]
    fn test_fallback_result() {
        let ids = vec!["f1".to_string(), "f2".to_string()];
        let result = JudgeResult::fallback(&ids);

